seo.schema:
{
    "@context": "https://schema.org",
    "@graph": [
        {
            "@type": "PestControlService",
            "@id": "{website}/#localbusiness",
            "name": "{business}",
            "url": "{website}",
            "telephone": "{tel}",
            "description": "{business} provides professional pest control services across {state}, including cockroach, termite, mosquito, rodent, and wildlife control for homes and businesses in the communities we serve.",
            "areaServed": {
                "@type": "State",
                "name": "{state}"
            },
            "priceRange": "$$",
            "openingHours": "Mo-Fr 08:00-18:00, Sa 09:00-13:00"
        },
        {
            "@type": "WebSite",
            "@id": "{website}/#website",
            "url": "{website}",
            "name": "{business}",
            "publisher": {
                "@id": "{website}/#localbusiness"
            }
        }
    ]
}
